DROP INDEX idx_unique_responsibility_asset_role_type_group_deleted_flag;
DROP INDEX idx_unique_responsibility_asset_role_type_user_deleted_flag;

CREATE UNIQUE INDEX idx_unique_responsibility_asset_role_type_group_deleted_flag ON "responsibility" (asset_id, role_id, responsible_type, user_id, deleted_flag)
  WHERE deleted_flag = false and relation_id is null;

CREATE UNIQUE INDEX idx_unique_responsibility_asset_role_type_user_deleted_flag ON "responsibility" (asset_id, role_id, responsible_type, group_id, deleted_flag)
  WHERE deleted_flag = false and relation_id is null;

CREATE UNIQUE INDEX idx_unique_resp_asset_role_type_user_relation_deleted_flag ON "responsibility" (asset_id, role_id, responsible_type, user_id, relation_id, deleted_flag)
  WHERE deleted_flag = false;

CREATE UNIQUE INDEX idx_unique_resp_asset_role_type_group_relation_deleted_flag ON "responsibility" (asset_id, role_id, responsible_type, group_id, relation_id, deleted_flag)
  WHERE deleted_flag = false
